// src/services/WorkspaceService.ts
var WorkspaceService = class {
  constructor(env, executionCtx) {
    this.env = env;
    this.executionCtx = executionCtx;
    this.audit = new AuditService(env, executionCtx);
  }
  static {
    __name(this, "WorkspaceService");
  }
  audit;
  async listByUser(userId) {
    const { results } = await this.env.DB.prepare(
      `SELECT w.id, w.name, w.slug, m.role, w.ownerId FROM workspaces w
       JOIN workspace_members m ON w.id = m.workspaceId WHERE m.userId = ? ORDER BY m.joinedAt ASC`
    ).bind(userId).all();
    return results;
  }
  async getById(id) {
    return await this.env.DB.prepare("SELECT * FROM workspaces WHERE id = ?").bind(id).first();
  }
  async update(id, actorId, data) {
    if (data.name) {
      await this.env.DB.prepare("UPDATE workspaces SET name = ?, updatedAt = ? WHERE id = ?").bind(data.name, Date.now(), id).run();
    }
    await this.audit.record({
      eventName: "workspace.updated",
      workspaceId: id,
      userId: actorId,
      properties: { updates: data }
    });
    return true;
  }
  async createInvite(workspaceId, actorId, role) {
    const now = Date.now();
    const { count } = await this.env.DB.prepare(
      "SELECT COUNT(*) as count FROM invites WHERE workspaceId = ? AND revokedAt IS NULL AND (expiresAt IS NULL OR expiresAt > ?)"
    ).bind(workspaceId, now).first();
    if (count >= 10) throw new Error("LIMIT_EXCEEDED");
    const id = crypto.randomUUID();
    const token = crypto.randomUUID();
    const expiresAt = now + 7 * 24 * 60 * 60 * 1e3;
    await this.env.DB.prepare(
      "INSERT INTO invites (id, workspaceId, token, role, createdAt, expiresAt, invitedBy) VALUES (?, ?, ?, ?, ?, ?, ?)"
    ).bind(id, workspaceId, token, role, now, expiresAt, actorId).run();
    await this.audit.record({
      eventName: Events.WORKSPACE_INVITE,
      workspaceId,
      userId: actorId,
      properties: { role, inviteId: id }
    });
    return { token, expiresAt, role };
  }
  async join(userId, token) {
    const now = Date.now();
    const invite = await this.env.DB.prepare("SELECT * FROM invites WHERE token = ?").bind(token).first();
    if (!invite) throw new Error("NOT_FOUND");
    if (invite.revokedAt) throw new Error("REVOKED");
    if (invite.expiresAt && invite.expiresAt < now) throw new Error("EXPIRED");
    await this.env.DB.prepare(
      "INSERT OR IGNORE INTO workspace_members (userId, workspaceId, role, joinedAt, invitedBy) VALUES (?, ?, ?, ?, ?)"
    ).bind(userId, invite.workspaceId, invite.role || "Member", now, invite.invitedBy || null).run();
    await this.audit.record({
      eventName: "workspace.member_joined",
      workspaceId: invite.workspaceId,
      userId,
      properties: { inviteId: invite.id }
    });
    return invite.workspaceId;
  }
  async listMembers(workspaceId) {
    const { results } = await this.env.DB.prepare(
      `SELECT u.id as userId, u.email, u.name, u.avatarUrl, m.role, m.joinedAt FROM workspace_members m
       JOIN users u ON u.id = m.userId WHERE m.workspaceId = ?`
    ).bind(workspaceId).all();
    return results;
  }
  async removeMember(workspaceId, actorId, targetUserId) {
    if (actorId === targetUserId) throw new Error("CANNOT_REMOVE_SELF");
    const targetMembership = await this.env.DB.prepare(
      "SELECT role FROM workspace_members WHERE workspaceId = ? AND userId = ?"
    ).bind(workspaceId, targetUserId).first();
    if (!targetMembership) throw new Error("NOT_FOUND");
    if (targetMembership.role === "Owner") throw new Error("CANNOT_REMOVE_OWNER");
    await this.env.DB.prepare("DELETE FROM workspace_members WHERE workspaceId = ? AND userId = ?").bind(workspaceId, targetUserId).run();
    await this.audit.record({
      eventName: Events.WORKSPACE_MEMBER_REMOVED,
      workspaceId,
      userId: actorId,
      properties: { removedUserId: targetUserId }
    });
    return true;
  }
  async revokeInvite(workspaceId, actorId, inviteId) {
    await this.env.DB.prepare("UPDATE invites SET revokedAt = ? WHERE id = ? AND workspaceId = ?").bind(Date.now(), inviteId, workspaceId).run();
    await this.audit.record({
      eventName: "workspace.invite_revoked",
      workspaceId,
      userId: actorId,
      properties: { inviteId }
    });
    return true;
  }
};

// src/controllers/WorkspaceController.ts
var WorkspaceController = class {
  static {
    __name(this, "WorkspaceController");
  }
  // 1. List Workspaces
  static async list(c) {
    const user = c.get("user");
    const service = new WorkspaceService(c.env);
    const results = await service.listByUser(user.id);
    return c.json({ workspaces: results });
  }
  // 2. Join Workspace
  static async join(c) {
    const user = c.get("user");
    const { token } = c.req.valid("json");
    const service = new WorkspaceService(c.env, c.executionCtx);
    try {
      const workspaceId = await service.join(user.id, token);
      return c.json({ success: true, workspaceId });
    } catch (err) {
      if (err.message === "NOT_FOUND") throw new HTTPException(404, { message: "Invite invalid" });
      if (err.message === "REVOKED") throw new HTTPException(403, { message: "Invite revoked" });
      if (err.message === "EXPIRED") throw new HTTPException(403, { message: "Invite expired" });
      throw err;
    }
  }
  // 3. Update Workspace
  static async update(c) {
    const user = c.get("user");
    const ws = c.get("workspace");
    const body = c.req.valid("json");
    const service = new WorkspaceService(c.env, c.executionCtx);
    await service.update(ws.id, user.id, body);
    return c.json({ success: true });
  }
  // 4. Create Invite
  static async createInvite(c) {
    const user = c.get("user");
    const ws = c.get("workspace");
    const { role } = c.req.valid("json");
    const service = new WorkspaceService(c.env, c.executionCtx);
    try {
      const invite = await service.createInvite(ws.id, user.id, role);
      return c.json(invite);
    } catch (err) {
      if (err.message === "LIMIT_EXCEEDED") throw new HTTPException(429, { message: "Max 10 active invites" });
      throw err;
    }
  }
  // 5. Revoke Invite
  static async revokeInvite(c) {
    const user = c.get("user");
    const ws = c.get("workspace");
    const inviteId = c.req.param("inviteId");
    if (!inviteId) throw new HTTPException(400, { message: "Missing inviteId" });
    const service = new WorkspaceService(c.env, c.executionCtx);
    await service.revokeInvite(ws.id, user.id, inviteId);
    return c.json({ success: true });
  }
  // 6. List Members
  static async listMembers(c) {
    const ws = c.get("workspace");
    const service = new WorkspaceService(c.env);
    const results = await service.listMembers(ws.id);
    return c.json(results);
  }
  // 7. Remove Member
  static async removeMember(c) {
    const currentUser = c.get("user");
    const ws = c.get("workspace");
    const targetUserId = c.req.param("userId");
    if (!targetUserId) throw new HTTPException(400, { message: "Missing userId" });
    const service = new WorkspaceService(c.env, c.executionCtx);
    try {
      await service.removeMember(ws.id, currentUser.id, targetUserId);
      return c.json({ success: true });
    } catch (err) {
      if (err.message === "NOT_FOUND") throw new HTTPException(404, { message: "Member not found" });
      if (err.message === "CANNOT_REMOVE_OWNER") throw new HTTPException(403, { message: "Cannot remove the owner" });
      if (err.message === "CANNOT_REMOVE_SELF") throw new HTTPException(400, { message: "Cannot remove yourself" });
      throw err;
    }
  }
};

