var AssetService = class {
  constructor(env) {
    this.env = env;
  }
  static {
    __name(this, "AssetService");
  }
  async getPresignedUploadUrls(sessionId, files, origin) {
    return files.map((f) => ({
      key: f.key,
      contentType: f.contentType,
      uploadUrl: `${origin}/v1/assets/file?key=${encodeURIComponent(f.key)}`
    }));
  }
  async put(key, body, contentType) {
    this.validatePath(key);
    return await this.env.R2.put(key, body, {
      httpMetadata: { contentType }
    });
  }
  async createMultipartUpload(key) {
    this.validatePath(key);
    return await this.env.R2.createMultipartUpload(key);
  }
  async resumeMultipartUpload(key, uploadId) {
    return this.env.R2.resumeMultipartUpload(key, uploadId);
  }
  async get(key) {
    const object2 = await this.env.R2.get(key);
    if (!object2) return null;
    return object2;
  }
  async delete(key) {
    return await this.env.R2.delete(key);
  }
  async getStorageUsage(userId) {
    const record2 = await this.env.DB.prepare(
      "SELECT r2StorageUsedBytes, r2StorageQuotaBytes FROM users WHERE id = ?"
    ).bind(userId).first();
    const FREE_QUOTA = 1073741824;
    const used = record2?.r2StorageUsedBytes || 0;
    const quota = record2?.r2StorageQuotaBytes || FREE_QUOTA;
    return { used, quota, percent: Math.round(used / quota * 100) };
  }
  validatePath(key) {
    if (!key.startsWith("sessions/") && !key.startsWith("screenshots/") && !key.startsWith("videos/") && !key.startsWith("audio/")) {
      throw new Error("INVALID_PATH");
    }
  }
};

