var SOPService = class {
  constructor(db) {
    this.db = db;
  }
  static {
    __name(this, "SOPService");
  }
  async getSOPById(sopId, workspaceId) {
    const row = await this.db.prepare("SELECT * FROM sops WHERE id = ? AND workspaceId = ?").bind(sopId, workspaceId).first();
    return row ?? null;
  }
  async listSOPs(workspaceId) {
    const result = await this.db.prepare("SELECT * FROM sops WHERE workspaceId = ? ORDER BY updatedAt DESC").bind(workspaceId).all();
    return result.results;
  }
  async createSOP(params) {
    const now = Date.now();
    await this.db.prepare(`INSERT INTO sops (id, workspaceId, sessionId, title, status, schemaVersion, createdAt, updatedAt)
                VALUES (?, ?, ?, ?, 'draft', '1.0', ?, ?)`).bind(params.id, params.workspaceId, params.sessionId, params.title, now, now).run();
    return await this.getSOPById(params.id, params.workspaceId);
  }
  async transitionStatus(sopId, workspaceId, targetStatus, actorId) {
    const sop = await this.getSOPById(sopId, workspaceId);
    if (!sop) throw new Error("SOP not found");
    const allowed = {
      draft: ["review"],
      review: ["published", "draft"],
      published: []
    };
    if (!allowed[sop.status].includes(targetStatus)) {
      throw new Error(`Cannot transition from ${sop.status} to ${targetStatus}`);
    }
    const now = Date.now();
    await this.db.prepare("UPDATE sops SET status = ?, updatedAt = ? WHERE id = ? AND workspaceId = ?").bind(targetStatus, now, sopId, workspaceId).run();
    return await this.getSOPById(sopId, workspaceId);
  }
  async getSteps(sopId, workspaceId) {
    const result = await this.db.prepare("SELECT * FROM steps WHERE sopId = ? AND workspaceId = ? ORDER BY stepIndex ASC").bind(sopId, workspaceId).all();
    return result.results.map((row) => {
      const parsed = StepSchema.safeParse(JSON.parse(row.content));
      if (!parsed.success) {
        console.error(`[SOPService] Step ${row.id} failed schema validation`, parsed.error);
        return JSON.parse(row.content);
      }
      return parsed.data;
    });
  }
  async updateStep(stepId, sopId, workspaceId, updates, actorId) {
    const sop = await this.getSOPById(sopId, workspaceId);
    if (!sop) throw new Error("SOP not found");
    if (sop.status === "published") {
      throw new Error("Cannot edit steps on a published SOP. Fork first.");
    }
    const existing = await this.db.prepare("SELECT * FROM steps WHERE id = ? AND sopId = ? AND workspaceId = ?").bind(stepId, sopId, workspaceId).first();
    if (!existing) throw new Error("Step not found");
    const currentContent = JSON.parse(existing.content);
    const newContent = { ...currentContent, ...updates };
    const validated = StepSchema.safeParse(newContent);
    if (!validated.success) {
      throw new Error(`Step update failed schema validation: ${validated.error.message}`);
    }
    const now = Date.now();
    await this.db.prepare(`UPDATE steps SET content = ?, version = version + 1, updatedAt = ?
                WHERE id = ? AND sopId = ? AND workspaceId = ?`).bind(JSON.stringify(validated.data), now, stepId, sopId, workspaceId).run();
  }
  async forkToNewDraft(sopId, workspaceId, actorId) {
    const source = await this.getSOPById(sopId, workspaceId);
    if (!source) throw new Error("Source SOP not found");
    if (source.status !== "published") throw new Error("Can only fork a published SOP");
    const newId = crypto.randomUUID();
    const newSop = await this.createSOP({
      id: newId,
      workspaceId,
      sessionId: source.sessionId,
      title: `${source.title} (Draft)`
    });
    const sourceSteps = await this.db.prepare("SELECT * FROM steps WHERE sopId = ? AND workspaceId = ? ORDER BY stepIndex ASC").bind(sopId, workspaceId).all();
    const now = Date.now();
    for (const step of sourceSteps.results) {
      await this.db.prepare(`INSERT INTO steps (id, sopId, workspaceId, stepIndex, type, content, version, createdAt, updatedAt)
                  VALUES (?, ?, ?, ?, ?, ?, 1, ?, ?)`).bind(crypto.randomUUID(), newId, workspaceId, step.stepIndex, step.type, step.content, now, now).run();
    }
    return newSop;
  }
};

