// src/handlers/scheduled.ts
async function handleScheduled(event, env, ctx) {
  console.log("[SCHEDULED] Running platform maintenance...");
  ctx.waitUntil((async () => {
    const fourteenDaysAgo = Date.now() - 14 * 24 * 60 * 60 * 1e3;
    await env.DB.prepare('DELETE FROM debug_logs WHERE timestamp < datetime(?, "unixepoch")').bind(Math.floor(fourteenDaysAgo / 1e3)).run().catch((err) => console.error("[SCHEDULED] Debug logs cleanup failed:", err));
  })());
  ctx.waitUntil((async () => {
    await env.DB.prepare("DELETE FROM invites WHERE expiresAt < ? AND revokedAt IS NULL").bind(Date.now()).run().catch((err) => console.error("[SCHEDULED] Invites cleanup failed:", err));
  })());
}
__name(handleScheduled, "handleScheduled");

