var PipelineProcessor = class {
  constructor(env) {
    this.env = env;
    this.audit = new AuditService(env);
  }
  static {
    __name(this, "PipelineProcessor");
  }
  audit;
  async process(job) {
    const { sessionId, userId } = job;
    const now = Date.now();
    try {
      await this.audit.record({
        eventName: "pipeline.started",
        userId,
        sessionId,
        properties: { ...job.requestedOutputs }
      });
      console.log(`[PIPELINE] Starting: ${sessionId}`);
      await this.env.DB.prepare(
        "UPDATE sessions SET status = ?, updatedAt = ? WHERE id = ?"
      ).bind("processing", now, sessionId).run();
      if (job.r2JsonKey) {
        const obj = await this.env.R2.get(job.r2JsonKey);
        if (obj) {
          const envelope = await obj.json();
          envelope.metadata = envelope.metadata || {};
          envelope.metadata.processedAt = Date.now();
          envelope.metadata.outputs = job.requestedOutputs;
          await this.env.R2.put(job.r2JsonKey, JSON.stringify(envelope), {
            httpMetadata: { contentType: "application/json" }
          });
        }
      }
      await this.env.DB.prepare(
        "UPDATE sessions SET status = ?, pipelinePath = ?, updatedAt = ? WHERE id = ?"
      ).bind("ready", "cloud", Date.now(), sessionId).run();
      await this.audit.record({
        eventName: "pipeline.completed",
        userId,
        sessionId,
        properties: { durationMs: Date.now() - now }
      });
      console.log(`[PIPELINE] Done: ${sessionId}`);
    } catch (err) {
      console.error(`[PIPELINE] Failed for ${sessionId}:`, err.message);
      await this.env.DB.prepare(
        "UPDATE sessions SET status = ?, errorReason = ?, updatedAt = ? WHERE id = ?"
      ).bind("failed", err.message, Date.now(), sessionId).run();
      await this.audit.record({
        eventName: "pipeline.failed",
        userId,
        sessionId,
        properties: { error: err.message }
      });
      throw err;
    }
  }
};

// src/handlers/queue.ts
async function handleQueue(batch, env, ctx) {
  const processor = new PipelineProcessor(env);
  for (const message of batch.messages) {
    try {
      console.log(`[QUEUE] Processing message ${message.id} for session ${message.body.sessionId}`);
      await processor.process(message.body);
      message.ack();
    } catch (err) {
      console.error(`[QUEUE] Failed to process message ${message.id}:`, err.message);
      if (message.attempts > 3) {
        console.error(`[QUEUE] Message ${message.id} exhausted max retries. Moving to terminal failure.`);
        const body = message.body;
        await env.DB.prepare(
          "UPDATE sessions SET status = ?, errorReason = ?, updatedAt = ? WHERE id = ?"
        ).bind("failed", "Max retries exceeded", Date.now(), body.sessionId).run();
        const { writeAuditLog: writeAuditLog2 } = await Promise.resolve().then(() => (init_audit(), audit_exports));
        await writeAuditLog2(env, {
          actorId: body.userId,
          action: "pipeline.terminal_failure",
          workspaceId: body.workspaceId || "unknown",
          targetId: body.sessionId,
          metadata: { error: "Max retries exceeded", messageId: message.id }
        });
        message.ack();
      } else {
        message.retry();
      }
    }
  }
}
__name(handleQueue, "handleQueue");

